@namespace sv_a62fabf86fcd47cda3f4cc7a395ecb87.Components.Pages.Apply

<nav aria-label="Application steps" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <li class="text-center flex-fill @(isCurrent ? "step-current" : isCompleted ? "step-completed" : "step-future")"
                role="button"
