@using sv_a62fabf86fcd47cda3f4cc7a395ecb87.Models

@namespace sv_a62fabf86fcd47cda3f4cc7a395ecb87.Components.Pages.Apply
@using sv_a62fabf86fcd47cda3f4cc7a395ecb87.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (!Model.IsValid())
        {
            ErrorMessage = "Please fill in all required fields.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            try
            {
                var isValid = await ValidateEmail(Model.Email);
                if (!isValid)
                {
                    ErrorMessage = "Please enter a valid email address.";
                    return;
                }
            }
            finally
            {
                IsValidating = false;
            }
        }

        await OnNext.InvokeAsync();
    }
}

