@page "/apply"
@rendermode InteractiveServer
@namespace sv_a62fabf86fcd47cda3f4cc7a395ecb87.Components.Pages.Apply
@using sv_a62fabf86fcd47cda3f4cc7a395ecb87.Models

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (SubmittedId.HasValue)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">&#10003; Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@SubmittedId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep"
                       CompletedSteps="_completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personalInfo"
                                  ValidateEmail="ApplicationService.ValidateEmailAsync"
                                  OnNext="() => AdvanceStep(0)" />
                break;
            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="() => AdvanceStep(1)"
                                 OnBack="() => GoToStep(_currentStep - 1)" />
                break;
            case 2:
                <ReferencesStep References="_references"
                                OnNext="() => AdvanceStep(2)"
                                OnBack="() => GoToStep(_currentStep - 1)" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="_coverLetter"
                                 OnNext="() => AdvanceStep(3)"
                                 OnBack="() => GoToStep(_currentStep - 1)" />
                break;
            case 4:
                <ReviewStep Personal="_personalInfo"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="@_coverLetter"
                            OnEditSection="GoToStep"
                            OnBack="() => GoToStep(_currentStep - 1)"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();
    private int? SubmittedId;

    // Form state
    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private readonly List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };
    private string _coverLetter = "";

    private void AdvanceStep(int completedStep)
    {
        _completedSteps.Add(completedStep);
        _currentStep = completedStep + 1;
    }

    private void GoToStep(int step)
    {
        if (step >= 0 && step <= 4)
            _currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            _personalInfo.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter
        );

        SubmittedId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

.step-indicator .step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
}

.step-completed {
    cursor: pointer;
}

.step-future {
    opacity: 0.5;
}

